// TaskServiceServer is the server API for TaskService service.
// All implementations must embed UnimplementedTaskServiceServer
// for forward compatibility.
//
// TaskService is the single gRPC service exposed by CodeValdWork.
// All operations are scoped to an agency via agency_id.
type TaskServiceServer interface {
	// CreateTask creates a new task for the agency in PENDING status.
	// Error: ALREADY_EXISTS if a task with the same ID exists.
	// Error: INVALID_ARGUMENT if required fields (title) are missing.
	CreateTask(context.Context, *CreateTaskRequest) (*CreateTaskResponse, error)
	// GetTask retrieves a single task by ID within the agency.
	// Error: NOT_FOUND if the task does not exist.
	GetTask(context.Context, *GetTaskRequest) (*GetTaskResponse, error)
	// GetTaskByName retrieves a task by its project-scoped name (task_name)
	// within a project (project_name). Falls back to ID lookup when task_name
	// looks like a UUID.
	// Error: NOT_FOUND if no task with that name exists in the project.
	GetTaskByName(context.Context, *GetTaskByNameRequest) (*GetTaskByNameResponse, error)
	// UpdateTask replaces mutable task fields.
	// Status transitions are validated server-side.
	// Error: NOT_FOUND if the task does not exist.
	// Error: FAILED_PRECONDITION if the status transition is invalid OR
	// if the pending → in_progress transition is gated by non-terminal
	// blocker tasks (carries a BlockedByInfo detail).
	UpdateTask(context.Context, *UpdateTaskRequest) (*UpdateTaskResponse, error)
	// DeleteTask permanently removes a task.
	// Error: NOT_FOUND if the task does not exist.
	DeleteTask(context.Context, *DeleteTaskRequest) (*DeleteTaskResponse, error)
	// ListTasks returns all tasks for the agency matching the filter.
	// Returns an empty list (not an error) when no tasks match.
	ListTasks(context.Context, *ListTasksRequest) (*ListTasksResponse, error)
	// AssignTask sets the agent currently responsible for a task by writing
	// the `assigned_to` graph edge. Replaces any prior assignee.
	// Error: NOT_FOUND if the task or agent does not exist.
	AssignTask(context.Context, *AssignTaskRequest) (*AssignTaskResponse, error)
	// UnassignTask removes any outbound `assigned_to` edge from the task.
	// Idempotent. Error: NOT_FOUND only if the task itself is missing.
	UnassignTask(context.Context, *UnassignTaskRequest) (*UnassignTaskResponse, error)
	// FailTodo marks a TaskTodo as failed and runs the full cascade:
	//   - blockDependentTodos — cascade-fails every blocked todo that
	//     (transitively) depended on this one.
	//   - maybeCompleteParentTask — marks the parent Task failed once all
	//     child todos are terminal.
	//
	// This is the same logic CodeValdWork executes when it receives
	// ai.task.failed from CodeValdAI, but exposed as a direct RPC for
	// operational use (manual override, QA testing).
	//
	// Error: NOT_FOUND if the todo does not exist.
	FailTodo(context.Context, *FailTodoRequest) (*FailTodoResponse, error)
	// ListTaskTodos returns TaskTodos for the agency, optionally filtered by
	// workflow_run_id. Returns an empty list (not an error) when none match.
	ListTaskTodos(context.Context, *ListTaskTodosRequest) (*ListTaskTodosResponse, error)
	// UpsertAgent creates or merges an Agent vertex keyed by the natural key
	// (agency_id, agent.agent_id).
	UpsertAgent(context.Context, *UpsertAgentRequest) (*UpsertAgentResponse, error)
	// GetAgent reads an Agent by entity ID.
	// Error: NOT_FOUND if the agent does not exist.
	GetAgent(context.Context, *GetAgentRequest) (*GetAgentResponse, error)
	// ListAgents returns every Agent in the agency.
	ListAgents(context.Context, *ListAgentsRequest) (*ListAgentsResponse, error)
	// CreateTaskInProject creates a task and immediately adds it as a member of
	// the given project. The server auto-generates task_name using the project's
	// task_prefix (e.g. "MVP-001", "MVP-002").
	// Error: NOT_FOUND if the project does not exist.
	// Error: INVALID_ARGUMENT if task title is empty.
	CreateTaskInProject(context.Context, *CreateTaskInProjectRequest) (*CreateTaskInProjectResponse, error)
	// CreateProject creates a new Project vertex.
	// Error: ALREADY_EXISTS if the project ID is already taken.
	// Error: INVALID_ARGUMENT if name is empty.
	CreateProject(context.Context, *CreateProjectRequest) (*CreateProjectResponse, error)
	// GetProject retrieves a single Project by entity ID.
	// Error: NOT_FOUND if the project does not exist.
	GetProject(context.Context, *GetProjectRequest) (*GetProjectResponse, error)
	// GetProjectByName retrieves a single Project by its slug (project_name).
	// Falls back to ID lookup when the value looks like a UUID.
	// Error: NOT_FOUND if no project with that name exists.
	GetProjectByName(context.Context, *GetProjectByNameRequest) (*GetProjectByNameResponse, error)
	// UpdateProject patches the mutable fields of an existing Project.
	UpdateProject(context.Context, *UpdateProjectRequest) (*UpdateProjectResponse, error)
	// DeleteProject removes the project AND all inbound `member_of` edges.
	// Member tasks themselves are preserved.
	DeleteProject(context.Context, *DeleteProjectRequest) (*DeleteProjectResponse, error)
	// ListProjects returns every Project in the agency.
	ListProjects(context.Context, *ListProjectsRequest) (*ListProjectsResponse, error)
	// AddTaskToProject writes the `member_of` edge from task to project.
	// Idempotent — re-adding an existing membership succeeds without
	// creating a duplicate edge.
	AddTaskToProject(context.Context, *AddTaskToProjectRequest) (*AddTaskToProjectResponse, error)
	// RemoveTaskFromProject removes the `member_of` edge from task to project.
	// Error: NOT_FOUND if no membership existed.
	RemoveTaskFromProject(context.Context, *RemoveTaskFromProjectRequest) (*RemoveTaskFromProjectResponse, error)
	// ListTasksInProject returns the tasks belonging to the given project via
	// inbound `member_of` edges.
	ListTasksInProject(context.Context, *ListTasksInProjectRequest) (*ListTasksInProjectResponse, error)
	// ListProjectsForTask returns the projects a task belongs to via outbound
	// `member_of` edges.
	ListProjectsForTask(context.Context, *ListProjectsForTaskRequest) (*ListProjectsForTaskResponse, error)
	// CreateRelationship validates the (label, from_id, to_id) triple against
	// the Work edge-label whitelist and creates the edge. Idempotent — a
	// matching pre-existing edge is returned without creating a duplicate.
	// Error: INVALID_ARGUMENT (with InvalidRelationshipInfo detail) if the
	// triple is rejected; NOT_FOUND if an endpoint is missing.
	CreateRelationship(context.Context, *CreateRelationshipRequest) (*CreateRelationshipResponse, error)
	// DeleteRelationship removes the edge identified by (from_id, to_id, label).
	// Error: NOT_FOUND if no such edge exists.
	DeleteRelationship(context.Context, *DeleteRelationshipRequest) (*DeleteRelationshipResponse, error)
	// TraverseRelationships returns the single-hop edges incident on vertex_id
	// matching the given label and direction. Returns an empty list (not an
	// error) when no edges match.
	TraverseRelationships(context.Context, *TraverseRelationshipsRequest) (*TraverseRelationshipsResponse, error)
	// CreateWorkflowRun anchors a new orchestrated execution. The returned run
	// is in WORKFLOW_RUN_STATUS_PENDING. When the request name is empty the
	// server generates one of the form `pipeline-YYYY-MM-DD-HHMMSS-<6hex>`.
	// Error: ALREADY_EXISTS when (agency_id, name) collides with an existing
	// run; INVALID_ARGUMENT when name has leading/trailing whitespace
	// (FEAT-20260602-001).
	CreateWorkflowRun(context.Context, *CreateWorkflowRunRequest) (*CreateWorkflowRunResponse, error)
	// GetWorkflowRun reads the run vertex plus its full closure: every Task,
	// TaskTodo, and edge reachable from the run, plus the IDs of foreign
	// (cross-service) entities the run referenced.
	// Error: NOT_FOUND if the run does not exist.
	GetWorkflowRun(context.Context, *GetWorkflowRunRequest) (*GetWorkflowRunResponse, error)
	// ListWorkflowRuns returns every WorkflowRun in the agency, newest first.
	// When request.name is non-empty the result is filtered to runs whose
	// name matches exactly (at most one row) (FEAT-20260602-001).
	ListWorkflowRuns(context.Context, *ListWorkflowRunsRequest) (*ListWorkflowRunsResponse, error)
	// RollbackWorkflowRun initiates the compensation sequence for the given run
	// (FEAT-20260602-004). Valid only when the run is in failed or completed
	// status. Transitions: failed/completed → rolling_back → rolled_back (or
	// rollback_failed on partial failure).
	// Errors: NOT_FOUND, FAILED_PRECONDITION (wrong source status or already
	// rolling back), ABORTED (foreign run dependency — roll back the dependent
	// run first).
	RollbackWorkflowRun(context.Context, *RollbackWorkflowRunRequest) (*RollbackWorkflowRunResponse, error)
	// CancelWorkflowRun flips an in_progress WorkflowRun to the cancelling
	// transient state, cascades work.task.cancelled to every non-terminal Task
	// in the run, and publishes work.run.cancelling (FEAT-20260602-008). A
	// separate finalization step elsewhere transitions the run to cancelled
	// after the quiesce deadline elapses.
	//
	// Idempotent: a repeated call on an already-cancelling run returns the
	// stored envelope without re-firing events or shifting the deadline.
	//
	// Errors: NOT_FOUND, FAILED_PRECONDITION (run is in any status other than
	// in_progress or cancelling).
	CancelWorkflowRun(context.Context, *CancelWorkflowRunRequest) (*CancelWorkflowRunResponse, error)
	// IncrementFailureBudget atomically increments the
	// failure_pipelines_used counter on the root WorkflowRun identified by
	// workflow_run_id. Cross calls this at failure-dispatch time, before
	// creating a child recovery run, to gate against budget exhaustion.
	// Idempotent on child_run_id: repeated calls with the same child_run_id
	// do not double-increment and return the current counter state
	// (FEAT-20260602-007).
	// Errors: NOT_FOUND if the root run does not exist.
	IncrementFailureBudget(context.Context, *IncrementFailureBudgetRequest) (*IncrementFailureBudgetResponse, error)
	// TouchWorkflowRunLastEventAt bumps last_event_at on the identified run.
	// Best-effort: ignores NotFound. Called by Cross on every published event
	// that carries a workflow_run_id (FEAT-20260602-006).
	TouchWorkflowRunLastEventAt(context.Context, *TouchWorkflowRunLastEventAtRequest) (*TouchWorkflowRunLastEventAtResponse, error)
	// ListWorkflowRunsStaleSince returns all non-terminal, unpaused WorkflowRuns
	// whose last_event_at is before cutoff. Used by the Cross watchdog sweeper
	// to find runs eligible for a work.run.timeout event (FEAT-20260602-006).
	ListWorkflowRunsStaleSince(context.Context, *ListWorkflowRunsStaleSinceRequest) (*ListWorkflowRunsResponse, error)
	// ImportProject parses a JSON document describing a project and creates a
	// Project vertex, a Task vertex for each entry in "tasks", member_of edges
	// from every Task to the Project, and depends_on edges for each entry in a
	// task's "depends_on" array.
	// All imported tasks start in PENDING status; the original task ID
	// (e.g. "MVP-SF-001") is stored as a tag on each Task for traceability.
	// Error: INVALID_ARGUMENT if the document is malformed or missing required
	// fields ("project", non-empty "tasks", each task needs "id" and "title").
	ImportProject(context.Context, *ImportProjectRequest) (*ImportProjectResponse, error)
	mustEmbedUnimplementedTaskServiceServer()
}

